    /**
     * A self-description of the user as markdown text
     */
    aboutMe?: string;
    /**
     * A list of backup codes that can be used, if the user has no access to its Google Authenticator device
     */
    backupCodes?: Array<string> | null;
    group?: GroupWritable | null;
    /**
     * The secret used for Google authenticator
     */
    googleAuthenticatorSecret?: string | null;
    /**
     * The timezone the user prefers
     */
    timezone?: string | null;
    /**
     * The language/locale the user prefers
     */
    language?: string | null;
    /**
     * The email address of the user
     */
    email?: string | null;
    /**
     * True if the user wants to show his email address on his (public) profile
     */
    show_email_on_profile?: boolean;
    /**
     * The department the user is working
     */
    department?: string | null;
